// Check multiple threat sources
const url = $('Webhook').first().json.url;
const urlhausData = $('Check URLhaus Database').first().json;

// URLhaus check
const isInURLhaus = urlhausData.query_status === 'ok' && urlhausData.result && urlhausData.result.length > 0;

// Determine risk level
let risk = 'Safe';
let message = 'URL appears to be legitimate';
let confidence = 0.85;

if (isInURLhaus) {
  risk = 'Scam';
  message = `URL found in URLhaus threat database: ${urlhausData.result[0].threat || 'Unknown threat'}`;
  confidence = 0.99;
}

// Check for suspicious patterns
const suspiciousPatterns = [
  /bit\.ly/i,
  /tinyurl/i,
  /shortened/i,
  /goo\.gl/i
];

if (suspiciousPatterns.some(pattern => pattern.test(url)) && risk === 'Safe') {
  risk = 'Suspicious';
  message = 'URL uses a shortener service (may hide destination)';
  confidence = 0.65;
}

// Check for HTTP (not HTTPS)
if (url.startsWith('http://') && !url.includes('localhost')) {
  if (risk === 'Safe') {
    risk = 'Suspicious';
    confidence = 0.6;
  } else {
    confidence = Math.max(confidence, 0.9);
  }
  message = 'Not using secure HTTPS connection';
}

return [{
  json: {
    url: url,
    risk: risk,
    message: message,
    confidence: confidence,
    timestamp: new Date().toISOString(),
    details: {
      inURLhaus: isInURLhaus,
      urlhausData: isInURLhaus ? urlhausData.result[0] : null
    }
  }
}];
